import {
  BrowserRouter,
  Routes,
  Route,
  Navigate,
  useLocation,
} from "react-router-dom";
import Cookies from "js-cookie";
import { useState, useEffect } from "react";

import PermissionContext from "./context/PermissionContext";
import ProtectedRoute from "./components/ProtectedRoute";

import AdminLogin from "./pages/AdminLogin";
import Dashboard from "./pages/Dashboard";
import MyProfile from "./pages/MyProfile";
import UserManagement from "./pages/UserManagement";
import PaymentsManagement from "./pages/PaymentsManagement";
import EmployeeManagement from "./pages/EmployeeManagement";
import UserDetails from "./pages/UserDetails";
import SupportManagement from "./pages/SupportManagement";
import RoleManagement from "./pages/RoleManagement";
import PermissionManagement from "./pages/PermissionManagement";
import ProtectedLayout from "./layouts/ProtectedLayout";

function App() {
  const [permissions, setPermissions] = useState([]);
  const [isAuthenticated, setIsAuthenticated] = useState(
    () => !!Cookies.get("adminToken"),
  );

    useEffect(() => {
    const storedPermissions = JSON.parse(
      localStorage.getItem("permissions")
    );
    if (storedPermissions) {
      setPermissions(storedPermissions);
    }
  }, []);

  // Scroll to top on route change
  function ScrollToTop() {
    const { pathname } = useLocation();
    useEffect(() => {
      window.scrollTo(0, 0);
    }, [pathname]);
    return null;
  }

  return (
    <PermissionContext.Provider value={permissions}>
    <BrowserRouter>
      <ScrollToTop />
      <Routes>
        {/* Admin login page */}
        <Route path="/" element={<AdminLogin setAuth={setIsAuthenticated} />} />

        {/* Protected admin routes */}
        <Route element={<ProtectedLayout />}>
          <Route
            path="/dashboard"
            element={
              isAuthenticated ? <ProtectedRoute><Dashboard /></ProtectedRoute> : <Navigate to="/" replace />
            }
          />

          <Route
            path="/myprofile"
            element={
              isAuthenticated ? <ProtectedRoute><MyProfile /></ProtectedRoute> : <Navigate to="/" replace />
            }
          />

          <Route
            path="/users"
            element={
              isAuthenticated ? <ProtectedRoute><UserManagement /></ProtectedRoute> : <Navigate to="/" replace />
            }
          />

          <Route
            path="/users/:userId"
            element={
              isAuthenticated ? <ProtectedRoute><UserDetails /></ProtectedRoute> : <Navigate to="/" replace />
            }
          />

          <Route
            path="/payment"
            element={
              isAuthenticated ? (
                <ProtectedRoute>
                <PaymentsManagement />
                </ProtectedRoute>
              ) : (
                <Navigate to="/" replace />
              )
            }
          />

          <Route
            path="/support"
            element={
              isAuthenticated ? (
                <ProtectedRoute>
                <SupportManagement />
                </ProtectedRoute>
              ) : (
                <Navigate to="/" replace />
              )
            }
          />

          <Route
            path="/employee"
            element={
              isAuthenticated ? (
                <ProtectedRoute>
                <EmployeeManagement />
                </ProtectedRoute>
              ) : (
                <Navigate to="/" replace />
              )
            }
          />

          <Route
            path="/roles"
            element={
              isAuthenticated ? <ProtectedRoute><RoleManagement /></ProtectedRoute> : <Navigate to="/" replace />
            }
          />

          <Route
            path="/permissions"
            element={
              isAuthenticated ? (
                <PermissionManagement />
              ) : (
                <Navigate to="/" replace />
              )
            }
          />
        </Route>

        {/* 404 fallback */}
        <Route path="*" element={<div>404 - Page not found</div>} />
      </Routes>
    </BrowserRouter>
    </PermissionContext.Provider>
  );
}

export default App;
